function TruckingQuotation(n,t){var a=this,e=$("#"+n);this.tabID=n,this.calculateDetail=function(n){var t=$(n).closest(".transaction-detail-row"),e=parseInt(unformatCurrency(t.find("[name='qty[]']").val()))*parseInt(unformatCurrency(t.find("[name='price[]']").val()));t.find("[name='subtotal[]']").val(e).blur(),a.calculateTotal()},this.calculateTotal=function(){var n=0;e.find("[name='subtotal[]']").each(function(){n+=parseInt(unformatCurrency($(this).val()))||0}),e.find("[name='total']").val(n).blur()},this.afterRemoveRowHandler=function(){a.calculateTotal()},this.rebindEl=function(){bindEl(e.find("[name='qty[]']"),"change",function(){a.calculateDetail(this)}),bindEl(e.find("[name='price[]']"),"change",function(){a.calculateDetail(this)})},this.loadOnReady=function(){a.rebindEl(),e.find("[name='price[]'], [name='qty[]']").change(function(){a.calculateDetail(this)}),e.find("[name=btnAddRows]").on("click",function(){addNewTemplateRow("quotation-row-template",null,null,a.rebindEl)}),(!t.rsDetail||t.rsDetail.length<=0)&&addNewTemplateRow("quotation-row-template",null,null,a.rebindEl)}}